  1→package com.voicedoc.app;
  2→
  3→import android.content.Intent;
  4→import android.database.Cursor;
  5→import android.net.Uri;
  6→import android.os.Bundle;
  7→import android.provider.OpenableColumns;
  8→import android.view.View;
  9→import android.widget.*;
 10→import androidx.appcompat.app.AppCompatActivity;
 11→import com.chaquo.python.PyObject;
 12→import com.chaquo.python.Python;
 13→import com.chaquo.python.android.AndroidPlatform;
 14→import java.io.*;
 15→
 16→public class MainActivity extends AppCompatActivity {
 17→    private TextView tvAudioName, tvDocName, tvStatus, tvResult;
 18→    private ProgressBar progressBar;
 19→    private Button btnCompare;
 20→    private ScrollView scrollResult;
 21→    private String audioPath = "", docPath = "";
 22→
 23→    @Override
 24→    protected void onCreate(Bundle savedInstanceState) {
 25→        super.onCreate(savedInstanceState);
 26→        setContentView(R.layout.activity_main);
 27→
 28→        tvAudioName = findViewById(R.id.tvAudioName);
 29→        tvDocName = findViewById(R.id.tvDocName);
 30→        tvStatus = findViewById(R.id.tvStatus);
 31→        tvResult = findViewById(R.id.tvResult);
 32→        progressBar = findViewById(R.id.progressBar);
 33→        btnCompare = findViewById(R.id.btnCompare);
 34→        scrollResult = findViewById(R.id.scrollResult);
 35→
 36→        if (!Python.isStarted()) {
 37→            Python.start(new AndroidPlatform(this));
 38→        }
 39→
 40→        findViewById(R.id.btnPickAudio).setOnClickListener(v -> pickFile("audio/*", 1));
 41→        findViewById(R.id.btnPickDoc).setOnClickListener(v -> pickFile("application/*", 2));
 42→        btnCompare.setOnClickListener(v -> startCompare());
 43→
 44→        handleShareIntent(getIntent());
 45→    }
 46→
 47→    @Override
 48→    protected void onNewIntent(Intent intent) {
 49→        super.onNewIntent(intent);
 50→        handleShareIntent(intent);
 51→    }
 52→
 53→    private void handleShareIntent(Intent intent) {
 54→        if (intent == null) return;
 55→        String action = intent.getAction();
 56→        if (Intent.ACTION_SEND.equals(action)) {
 57→            Uri uri = intent.getParcelableExtra(Intent.EXTRA_STREAM);
 58→            if (uri != null) importFile(uri);
 59→        }
 60→    }
 61→
 62→    private void pickFile(String mimeType, int requestCode) {
 63→        Intent i = new Intent(Intent.ACTION_GET_CONTENT);
 64→        i.setType(mimeType);
 65→        i.addCategory(Intent.CATEGORY_OPENABLE);
 66→        startActivityForResult(i, requestCode);
 67→    }
 68→
 69→    @Override
 70→    protected void onActivityResult(int requestCode, int resultCode, Intent data) {
 71→        super.onActivityResult(requestCode, resultCode, data);
 72→        if (resultCode != RESULT_OK || data == null) return;
 73→        Uri uri = data.getData();
 74→        if (uri == null) return;
 75→
 76→        String path = copyToCache(uri);
 77→        if (path == null) return;
 78→
 79→        String name = getFileName(uri);
 80→        if (requestCode == 1) {
 81→            audioPath = path;
 82→            tvAudioName.setText(name);
 83→        } else {
 84→            docPath = path;
 85→            tvDocName.setText(name);
 86→        }
 87→    }
 88→
 89→    private void importFile(Uri uri) {
 90→        String path = copyToCache(uri);
 91→        if (path == null) return;
 92→        String name = getFileName(uri).toLowerCase();
 93→        if (name.endsWith(".wav") || name.endsWith(".mp3") || name.endsWith(".m4a") ||
 94→            name.endsWith(".flac") || name.endsWith(".amr") || name.endsWith(".silk")) {
 95→            audioPath = path;
 96→            tvAudioName.setText(getFileName(uri));
 97→        } else {
 98→            docPath = path;
 99→            tvDocName.setText(getFileName(uri));
100→        }
101→        tvStatus.setText("已从微信导入文件");
102→    }
103→
104→    private String copyToCache(Uri uri) {
105→        try {
106→            InputStream is = getContentResolver().openInputStream(uri);
107→            String name = getFileName(uri);
108→            File out = new File(getCacheDir(), name);
109→            FileOutputStream fos = new FileOutputStream(out);
110→            byte[] buf = new byte[8192];
111→            int n;
112→            while ((n = is.read(buf)) != -1) fos.write(buf, 0, n);
113→            fos.close();
114→            is.close();
115→            return out.getAbsolutePath();
116→        } catch (Exception e) {
117→            tvStatus.setText("文件导入失败: " + e.getMessage());
118→            return null;
119→        }
120→    }
121→
122→    private String getFileName(Uri uri) {
123→        String name = "file";
124→        Cursor c = getContentResolver().query(uri, null, null, null, null);
125→        if (c != null && c.moveToFirst()) {
126→            int idx = c.getColumnIndex(OpenableColumns.DISPLAY_NAME);
127→            if (idx >= 0) name = c.getString(idx);
128→            c.close();
129→        }
130→        return name;
131→    }
132→
133→    private void startCompare() {
134→        if (audioPath.isEmpty() || docPath.isEmpty()) {
135→            tvStatus.setText("请先选择录音和文档");
136→            return;
137→        }
138→        btnCompare.setEnabled(false);
139→        progressBar.setVisibility(View.VISIBLE);
140→        tvStatus.setText("正在处理...");
141→
142→        new Thread(() -> {
143→            try {
144→                Python py = Python.getInstance();
145→                PyObject engine = py.getModule("engine");
146→                PyObject result = engine.callAttr("run_compare",
147→                    audioPath, docPath, getFilesDir().getAbsolutePath());
148→
149→                String summary = result.callAttr("get", "summary").toString();
150→                String details = result.callAttr("get", "details").toString();
151→
152→                runOnUiThread(() -> {
153→                    tvStatus.setText("对比完成");
154→                    tvResult.setText(summary + "\n\n" + details);
155→                    scrollResult.setVisibility(View.VISIBLE);
156→                    progressBar.setVisibility(View.GONE);
157→                    btnCompare.setEnabled(true);
158→                });
159→            } catch (Exception e) {
160→                runOnUiThread(() -> {
161→                    tvStatus.setText("错误: " + e.getMessage());
162→                    progressBar.setVisibility(View.GONE);
163→                    btnCompare.setEnabled(true);
164→                });
165→            }
166→        }).start();
167→    }
168→}
