"""Sherpa-ONNX 离线模型下载脚本

在手机首次使用前，可以先在电脑上下载模型，然后传到手机。
也可以在手机上直接运行此脚本下载。

模型：Paraformer中英文离线识别，约80MB
"""
import os, sys, zipfile, requests

# 使用sherpa-onnx官方提供的Paraformer中文模型
MODEL_URL = 'https://github.com/k2-fsa/sherpa-onnx/releases/download/asr-models/sherpa-onnx-paraformer-zh-2023-09-14.tar.bz2'
# 国内加速镜像
MIRROR_URLS = [
    'https://hub.nuaa.cf/k2-fsa/sherpa-onnx/releases/download/asr-models/sherpa-onnx-paraformer-zh-2023-09-14.tar.bz2',
    'https://ghproxy.com/https://github.com/k2-fsa/sherpa-onnx/releases/download/asr-models/sherpa-onnx-paraformer-zh-2023-09-14.tar.bz2',
    MODEL_URL,
]


def get_model_dir():
    """获取模型存储目录"""
    try:
        from kivy.utils import platform
        if platform == 'android':
            from android.storage import app_storage_path
            return os.path.join(app_storage_path(), 'models', 'paraformer')
    except:
        pass
    return os.path.join(os.path.expanduser('~'), '.sherpa-onnx', 'paraformer')


def is_model_ready(model_dir=None):
    """检查模型是否已下载"""
    if model_dir is None:
        model_dir = get_model_dir()
    return os.path.exists(os.path.join(model_dir, 'model.int8.onnx'))


def download_model(dest_dir=None, progress_cb=None):
    """下载Paraformer离线模型"""
    import tarfile, io

    if dest_dir is None:
        dest_dir = get_model_dir()
    os.makedirs(dest_dir, exist_ok=True)

    for url in MIRROR_URLS:
        try:
            if progress_cb:
                progress_cb(f'正在下载模型...')
            print(f'尝试下载: {url}')

            resp = requests.get(url, stream=True, timeout=30)
            resp.raise_for_status()

            total = int(resp.headers.get('content-length', 0))
            data = io.BytesIO()
            downloaded = 0

            for chunk in resp.iter_content(8192):
                data.write(chunk)
                downloaded += len(chunk)
                if total:
                    pct = int(downloaded * 100 / total)
                    mb = downloaded // 1024 // 1024
                    msg = f'下载模型: {pct}% ({mb}MB)'
                    if progress_cb:
                        progress_cb(msg)
                    if downloaded % (1024 * 1024) < 8192:
                        print(msg)

            data.seek(0)
            if progress_cb:
                progress_cb('正在解压模型...')
            print('正在解压...')

            with tarfile.open(fileobj=data, mode='r:bz2') as tar:
                # 解压到dest_dir，去掉顶层目录
                for member in tar.getmembers():
                    # 去掉第一层目录名
                    parts = member.name.split('/', 1)
                    if len(parts) > 1:
                        member.name = parts[1]
                        tar.extract(member, dest_dir)

            print(f'模型已下载到: {dest_dir}')
            if progress_cb:
                progress_cb('模型下载完成')
            return True

        except Exception as e:
            print(f'下载失败({url}): {e}')
            continue

    raise Exception('所有下载源均失败，请手动下载模型')


if __name__ == '__main__':
    dest = sys.argv[1] if len(sys.argv) > 1 else get_model_dir()
    if is_model_ready(dest):
        print(f'模型已存在: {dest}')
    else:
        download_model(dest, progress_cb=lambda m: print(m))

