   323→        // PCM bytes -> float samples (16-bit little-endian)
   324→        int numSamples = pcmBytes.length / 2;
   325→        float[] allSamples = new float[numSamples];
   326→        ByteBuffer bb = ByteBuffer.wrap(pcmBytes).order(ByteOrder.LITTLE_ENDIAN);
   327→        for (int i = 0; i < numSamples; i++) {
   328→            allSamples[i] = bb.getShort() / 32768.0f;
   329→        }
   330→
   331→        // 立体声 -> 单声道
   332→        float[] mono;
