   334→            int monoLen = numSamples / channels;
   335→            mono = new float[monoLen];
   336→            for (int i = 0; i < monoLen; i++) {
   337→                float sum = 0;
   338→                for (int c = 0; c < channels; c++) {
   339→                    sum += allSamples[i * channels + c];
