   364→    // ===== 线性插值重采样 =====
   365→    private float[] resample(float[] input, int fromRate, int toRate) {
   366→        double ratio = (double) fromRate / toRate;
   367→        int outputLen = (int) (input.length / ratio);
   368→        float[] output = new float[outputLen];
   369→        for (int i = 0; i < outputLen; i++) {
   370→            double srcIdx = i * ratio;
   371→            int idx = (int) srcIdx;
   372→            double frac = srcIdx - idx;
   373→            if (idx + 1 < input.length) {
   374→                output[i] = (float) (input[idx] * (1 - frac) + input[idx + 1] * frac);
   375→            } else if (idx < input.length) {
   376→                output[i] = input[idx];
   377→            }
   378→        }
   379→        return output;
   380→    }
