                        tvAsrTestResult.setText("✗ " + result);
                        tvAsrTestResult.setTextColor(0xFFF44336);
                    });
                }
            } catch (Exception e) {
                Log.e(TAG, "ASR测试失败", e);
                String errMsg = "测试失败: " + e.getMessage();
                runOnUiThread(() -> {
                    tvAsrTestResult.setText("✗ " + errMsg);
                    tvAsrTestResult.setTextColor(0xFFF44336);
                });
            }
        }).start();
    }

    private void testLlm() {
        String providerId = LLM_IDS[spinnerLlm.getSelectedItemPosition()];
        String apiKey = etLlmKey.getText().toString().trim();
        tvLlmTestResult.setText("正在测试...");
        tvLlmTestResult.setTextColor(0xFF666666);

        new Thread(() -> {
            String result;
            try {
                if (apiKey.isEmpty()) {
                    result = "请先输入API Key";
                } else {
                    if (!Python.isStarted()) {
                        Python.start(new AndroidPlatform(this));
                    }
                    Python py = Python.getInstance();
                    PyObject engine = py.getModule("engine");
                    result = engine.callAttr("test_llm", providerId, apiKey).toString();
                }

                if (result.contains("成功") || result.contains("连接成功") || result.contains("valid")) {
                    runOnUiThread(() -> {
                        tvLlmTestResult.setText("✓ " + result);
                        tvLlmTestResult.setTextColor(0xFF4CAF50);
                    });
                } else {
                    runOnUiThread(() -> {
                        tvLlmTestResult.setText("✗ " + result);
                        tvLlmTestResult.setTextColor(0xFFF44336);
                    });
                }
            } catch (Exception e) {
                Log.e(TAG, "LLM测试失败", e);
                String errMsg = "测试失败: " + e.getMessage();
                runOnUiThread(() -> {
                    tvLlmTestResult.setText("✗ " + errMsg);
                    tvLlmTestResult.setTextColor(0xFFF44336);
                });
            }
        }).start();
    }
}

