321→    // ===== 音频解码：支持所有格式(WAV/MP3/M4A/FLAC/AMR/OGG...) =====
322→    private float[] decodeAudio(String filepath) throws Exception {
323→        MediaExtractor extractor = new MediaExtractor();
324→        extractor.setDataSource(filepath);
325→
326→        // 查找音频轨道
327→        int trackIndex = -1;
328→        MediaFormat format = null;
329→        for (int i = 0; i < extractor.getTrackCount(); i++) {
330→            MediaFormat f = extractor.getTrackFormat(i);
331→            String mime = f.getString(MediaFormat.KEY_MIME);
332→            if (mime != null && mime.startsWith("audio/")) {
333→                trackIndex = i;
334→                format = f;
335→                break;
336→            }
337→        }
338→        if (trackIndex < 0) {
339→            throw new Exception("未找到音频轨道，文件可能不是音频格式");
340→        }
341→
342→        extractor.selectTrack(trackIndex);
343→        String mime = format.getString(MediaFormat.KEY_MIME);
344→        int sampleRate = format.getInteger(MediaFormat.KEY_SAMPLE_RATE);
345→        int channels = format.getInteger(MediaFormat.KEY_CHANNEL_COUNT);
346→        Log.i(TAG, "音频格式: " + mime + ", " + sampleRate + "Hz, " + channels + "ch");
347→
348→        ByteArrayOutputStream pcmOut = new ByteArrayOutputStream();
349→
350→        if ("audio/raw".equals(mime)) {
351→            // PCM WAV: 直接从extractor读取，不需要codec解码
352→            ByteBuffer buf = ByteBuffer.allocate(65536);
353→            while (extractor.readSampleData(buf, 0) >= 0) {
354→                int pos = buf.position();
355→                byte[] chunk = new byte[pos];
356→                buf.flip();
357→                buf.get(chunk);
358→                pcmOut.write(chunk);
359→                buf.clear();
360→                extractor.advance();
361→            }
362→        } else {
363→            // 压缩格式(MP3/AAC/FLAC/AMR等): 用MediaCodec解码
364→            MediaCodec codec = MediaCodec.createDecoderByType(mime);
365→            codec.configure(format, null, null, 0);
366→            codec.start();
367→
368→            MediaCodec.BufferInfo info = new MediaCodec.BufferInfo();
369→            boolean inputDone = false;
370→            boolean outputDone = false;
371→
372→            while (!outputDone) {
373→                // 送入压缩数据
374→                if (!inputDone) {
375→                    int inputIdx = codec.dequeueInputBuffer(10000);
376→                    if (inputIdx >= 0) {
377→                        ByteBuffer inputBuf = codec.getInputBuffer(inputIdx);
378→                        int size = extractor.readSampleData(inputBuf, 0);
379→                        if (size < 0) {
380→                            codec.queueInputBuffer(inputIdx, 0, 0, 0,
381→                                MediaCodec.BUFFER_FLAG_END_OF_STREAM);
382→                            inputDone = true;
383→                        } else {
384→                            codec.queueInputBuffer(inputIdx, 0, size,
385→                                extractor.getSampleTime(), 0);
386→                            extractor.advance();
387→                        }
388→                    }
389→                }
390→
391→                // 取出PCM数据
392→                int outputIdx = codec.dequeueOutputBuffer(info, 10000);
393→                if (outputIdx >= 0) {
394→                    if ((info.flags & MediaCodec.BUFFER_FLAG_END_OF_STREAM) != 0) {
395→                        outputDone = true;
396→                    }
397→                    if (info.size > 0) {
398→                        ByteBuffer outputBuf = codec.getOutputBuffer(outputIdx);
399→                        byte[] chunk = new byte[info.size];
400→                        outputBuf.get(chunk);
401→                        pcmOut.write(chunk);
402→                    }
403→                    codec.releaseOutputBuffer(outputIdx, false);
404→                } else if (outputIdx == MediaCodec.INFO_OUTPUT_FORMAT_CHANGED) {
405→                    MediaFormat outFmt = codec.getOutputFormat();
406→                    sampleRate = outFmt.getInteger(MediaFormat.KEY_SAMPLE_RATE);
407→                    channels = outFmt.getInteger(MediaFormat.KEY_CHANNEL_COUNT);
408→                    Log.i(TAG, "解码输出格式: " + sampleRate + "Hz, " + channels + "ch");
409→                }
410→            }
411→
412→            codec.stop();
413→            codec.release();
414→        }
415→
416→        extractor.release();
417→
418→        byte[] pcmBytes = pcmOut.toByteArray();
419→        if (pcmBytes.length < 100) {
420→            throw new Exception("音频解码后数据为空 (原格式: " + mime + ")");
421→        }
422→
423→        // PCM bytes -> float samples (16-bit little-endian)
424→        int numSamples = pcmBytes.length / 2;
425→        float[] allSamples = new float[numSamples];
426→        ByteBuffer bb = ByteBuffer.wrap(pcmBytes).order(ByteOrder.LITTLE_ENDIAN);
427→        for (int i = 0; i < numSamples; i++) {
428→            allSamples[i] = bb.getShort() / 32768.0f;
429→        }
430→
431→        // 立体声 -> 单声道
432→        float[] mono;
433→        if (channels > 1) {
434→            int monoLen = numSamples / channels;
435→            mono = new float[monoLen];
436→            for (int i = 0; i < monoLen; i++) {
437→                float sum = 0;
438→                for (int c = 0; c < channels; c++) {
439→                    sum += allSamples[i * channels + c];
440→                }
441→                mono[i] = sum / channels;
442→            }
443→        } else {
444→            mono = allSamples;
445→        }
446→
447→        // 重采样到16kHz
448→        if (sampleRate != 16000) {
449→            Log.i(TAG, "重采样: " + sampleRate + "Hz -> 16000Hz");
450→            mono = resample(mono, sampleRate, 16000);
451→        }
452→
453→        float durationSec = mono.length / 16000.0f;
454→        Log.i(TAG, "解码完成: " + mono.length + " samples, " +
455→            String.format("%.1f", durationSec) + "s @ 16kHz mono");
456→
457→        if (durationSec < 0.3f) {
458→            throw new Exception("音频太短 (" + String.format("%.1f", durationSec) + "秒)，无法识别");
459→        }
460→
461→        return mono;
462→    }
463→
464→    // ===== 线性插值重采样 =====
465→    private float[] resample(float[] input, int fromRate, int toRate) {
466→        double ratio = (double) fromRate / toRate;
467→        int outputLen = (int) (input.length / ratio);
468→        float[] output = new float[outputLen];
469→        for (int i = 0; i < outputLen; i++) {
470→            double srcIdx = i * ratio;
471→            int idx = (int) srcIdx;
472→            double frac = srcIdx - idx;
473→            if (idx + 1 < input.length) {
474→                output[i] = (float) (input[idx] * (1 - frac) + input[idx + 1] * frac);
475→            } else if (idx < input.length) {
476→                output[i] = input[idx];
477→            }
478→        }
479→        return output;
480→    }
