482→    // ===== Sherpa-ONNX 离线识别 =====
483→    private String transcribeSherpa(String audioFile) throws Exception {
484→        // 解码音频为16kHz单声道（支持WAV/MP3/M4A/FLAC/AMR/OGG等）
485→        float[] samples = decodeAudio(audioFile);
486→
487→        AssetManager assetManager = getAssets();
488→
489→        OfflineParaformerModelConfig paraformerConfig = new OfflineParaformerModelConfig();
490→        paraformerConfig.setModel("models/paraformer/model.int8.onnx");
491→
492→        OfflineModelConfig modelConfig = new OfflineModelConfig();
493→        modelConfig.setParaformer(paraformerConfig);
494→        modelConfig.setTokens("models/paraformer/tokens.txt");
495→        modelConfig.setNumThreads(4);
496→        modelConfig.setDebug(false);
497→
498→        OfflineRecognizerConfig config = new OfflineRecognizerConfig();
499→        config.setModelConfig(modelConfig);
500→        config.setDecodingMethod("greedy_search");
501→
502→        OfflineRecognizer recognizer = new OfflineRecognizer(assetManager, config);
503→
504→        OfflineStream stream = recognizer.createStream();
505→        stream.acceptWaveform(samples, 16000);
506→        recognizer.decode(stream);
507→
508→        OfflineRecognizerResult result = recognizer.getResult(stream);
509→        String text = result.getText();
510→
511→        stream.release();
512→        recognizer.release();
513→
514→        return text != null ? text.trim() : "";
515→    }
