# ===== Groq Whisper =====
def transcribe_groq(filepath, api_key=''):
    """Groq Whisper API - 注意：Groq不支持timestamp_granularities参数"""
    if not api_key:
        raise Exception('请先在设置中配置Groq API Key')

    with open(filepath, 'rb') as f:
        resp = requests.post('https://api.groq.com/openai/v1/audio/transcriptions',
            headers={'Authorization': 'Bearer %s' % api_key},
            files={'file': (os.path.basename(filepath), f, 'audio/wav')},
            data={'model': 'whisper-large-v3', 'language': 'zh',
                  'response_format': 'text'},
            timeout=180)

    if resp.status_code != 200:
        raise Exception('Groq API错误 HTTP %d: %s' % (resp.status_code, resp.text[:200]))

    result = resp.text
    if not result or result.startswith('{"error"'):
        raise Exception('Groq识别失败: %s' % result[:200])

    return result


# ===== FunASR 局域网 =====
def transcribe_funasr(filepath, server_url):
    """FunASR局域网服务"""
    try:
        r = requests.get('%s/health' % server_url, timeout=3)
        if r.status_code != 200:
            raise Exception('FunASR服务未响应')
    except requests.exceptions.ConnectionError:
        raise Exception('无法连接FunASR服务(%s)\n请确认手机和电脑在同一WiFi' % server_url)

    with open(filepath, 'rb') as f:
        resp = requests.post('%s/transcribe_file' % server_url,
            files={'file': (os.path.basename(filepath), f)}, timeout=600)

    if resp.status_code == 404:
        resp = requests.post('%s/transcribe' % server_url,
            json={'file_path': os.path.abspath(filepath)}, timeout=600)

    data = resp.json()
    if not data.get('success'):
        raise Exception(data.get('error', 'FunASR转写失败'))
    return data.get('text', '')


